import jibo = require('jibo');
import CircuitSaver from '../CircuitSaver';

const YEAR_IN_MS:number = 31536000000;

export default class Analytics {

    static _track: typeof CircuitSaver.prototype.track;
    static _playerAge:number = -1;

    static init(skill:CircuitSaver){
        this._track = skill.track;
        this._playerAge = -1;
        let speaker = jibo.lps.identity.getActiveSpeaker();
        if(speaker && speaker.idInfo && speaker.idInfo.id){
            jibo.kb.loop.getUserNodeById(speaker.idInfo.id, (err, looper:jibo.kb.UserNode)=>{
                if(!err && looper && looper.data && typeof looper.data.birthday === 'number'){
                    this._playerAge = Math.floor((Date.now() - looper.data.birthday) / YEAR_IN_MS);
                }
            });
        }
    }

    static calibrated(is_initial:boolean, success:boolean, after_face_lost:boolean){
        this._track('CircuitSaver Calibrated', {is_initial, success, player_age: this._playerAge, after_face_lost});
    }

    static collisionWarning(prompt_id:number){
        this._track('CircuitSaver Collision Warning', {prompt_id});
    }

    static gameFinished(score:number, replay_number:number){
        this._track('CircuitSaver Game Finished', {score, replay_number});
    }
}
