/// <reference path="../typings/index.d.ts" />
import jibo = require('jibo');
import THREE = require('@jibo/three');

class Pose{
    public animName:string;
    public headOrientation:THREE.Vector3;
    constructor(name:string, vec:{x:number,y:number,z:number}){
        this.animName = name;
        this.headOrientation = new THREE.Vector3(vec.x, vec.y, vec.z);
    }
}

let CENTER_POSES:Array<Pose> = [
    //Lean Back too risky for false positives right now. Also, face tracking isn't great at that angle
    //new Pose('Body_Lean_Back_01', {x: 0.6197788119316134, y: -6.455580747743994e-8, z: 0.7847765243572966}),
    new Pose('Body_Look_Center_Middle_01', {x: 0.9010769128799438, y: -5.551115123125783e-17, z: 0.4336593551128336}),
    new Pose('Body_Crouch_01', {x: 0.9895257949829321, y: -6.351618192512731e-8, z: 0.14435623937185668}),
    new Pose('Body_Lean_Forward_01', {x: 0.9526615142822263, y: -7.197626028521142e-8, z: -0.30403297580888083})
]

class BetterCenter {

    static getNearestLevelHeadPose():string{
        let up = new THREE.Vector3(0, 0, 1);
        let currentPosition:THREE.Vector3 = jibo.expression.features.head.direction;
        let currentAngleToUp = currentPosition.angleTo(up);
        let closestPose:Pose;
        let closestAngle:number = 2 * Math.PI;//initialize to impossibly-large value
        let currentAngle:number;
        for(let pose of CENTER_POSES){
            let poseAngleToUp = pose.headOrientation.angleTo(up);
            currentAngle = Math.abs(poseAngleToUp - currentAngleToUp);
            if(currentAngle < closestAngle){
                closestAngle = currentAngle;
                closestPose = pose;
            }
        }
        return closestPose.animName;
    }
}

export default BetterCenter;
