/// <reference path="../typings/index.d.ts" />
import {BeSkill, Options} from '@be/be-framework';
import jibo = require('jibo');
import BetterCenter from './BetterCenter';
import FaceWatcher from './FaceWatcher';
import Analytics from './analytics/Analytics';

let mainFlow: any = require('./flows/main');

export default class CircuitSaver extends BeSkill {

    public flow: any;
    public kbm: jibo.kb.Model;
    public root: jibo.kb.Node;
    private _blackboard: any;
    private _faceWatcher: FaceWatcher;

    /**
     * CircuitSaver skill constructor
     * @constructor
     * @param {String} [assetPack=''] The asset pack if loading from Be
     */
    constructor(assetPack?: Options) {
        super(assetPack);
        this.flow = null;
    }

    preload(done: (err?: any) => void): void {
        jibo.face.views.creator.registerClass(require('./GameView').default, 'GameView');
        this.kbm = jibo.kb.createModel('/circuit-saver');
        this.kbm.loadRoot((err, root) => {
            if (root) {
                this.root = root;
            }
            done();
        });

    }

    /**
     * Start the skill
     * @method open
     */
    open(result: any, refresh:boolean, previousSkillName:string, previousSkillOptions:any): void {
        if(refresh){
            this.cleanup(this.open.bind(this, result, false, previousSkillName, previousSkillOptions));
            return;
        }
        Analytics.init(this);

        //because we expect users to back away from the robot to use the camera, always re-enable listening during menus
        jibo.mim.silentMenus = false;

        jibo.face.views.forceEyeView();
        this._faceWatcher = new FaceWatcher();
        this._blackboard = {
            kbRoot: this.root,
            log: this.log,
            skill: this,
            BetterCenter:BetterCenter,
            faceWatcher: this._faceWatcher,
            Analytics: Analytics
        };
        const options = { assetPack: this.assetPack, enableLogging: true, blackboard: this._blackboard };
        this.flow = jibo.flow.run(mainFlow, options, (err, status) => {
            if (status != jibo.bt.Status.INTERRUPTED) {
                this.log.info('game exiting naturally');
                this.exit();
            }
        });
    }

    /**
     * Stop and unload the skill
     * @method close
     */
    close(done: () => void): void {
        jibo.face.views.creator.unregisterClass('GameView');
        this.kbm = null;
        this.cleanup(done);
    }

    cleanup(done: () => void):void{
        if(this._faceWatcher){
            this._faceWatcher.destroy();
            this._faceWatcher = null;
        }
        this._blackboard = null;

        if (this.flow) {
            let flowCleanupDone = ()=>{
                this.flow = null;
                this.cleanupViews(done);
            };
            this.flow.stopAndDestroy().then(flowCleanupDone).catch(flowCleanupDone);
        }
        else {
            this.cleanupViews(done);
        }
    }

    cleanupViews(done: () => void): void {
        let callback = this.cleanupViewfinder.bind(this, done);
        jibo.action.configure({orientToHJ: true});

        if (jibo.face.views.currentView) {
            if (jibo.face.views.currentView.id != 'eyeView') {
                jibo.face.views.changeView(
                    { removeAll: true, leaveEmpty: true },
                    () => { callback(); },
                    () => {
                        this.log.warn('failed to cleanup on exit');
                        callback();
                    }
                );
            }
            else{
                jibo.face.views.forceEyeView(
                    () => { callback(); },
                    null,
                    jibo.face.views.IN,
                    jibo.face.views.NONE,
                    () => {
                        this.log.warn('failed to cleanup on exit');
                        callback();
                    }
                );
            }
        }
        else {
            callback();
        }
    }

    cleanupViewfinder(done: () => void): void {
        jibo.media.setViewfinder(
            false,
            (err) => {
                if(err){
                    this.log.warn('failed to disable viewfinder on exit: ', err);
                }
                done();
            }
        );
    }
}
